def transition(state, action):
    s = dict(state)
    claims = [dict(c) for c in s.get("claims", [])]
    name = action.get("name")
    params = action.get("params") or {}

    def oldest_with(status):
        cid = params.get("claim_id")
        if cid is not None:
            for cl in claims:
                if cl.get("id") == cid and cl.get("status") == status:
                    return cl
            return None
        for cl in claims:
            if cl.get("status") == status:
                return cl
        return None

    if name == "submit":
        cid = int(s.get("next_id", 1))
        amount = params.get("amount")
        if amount is None:
            amount = s.get("pending_amount")
        if amount is None:
            amount = round(100.0 + 50.0 * cid, 2)
        amount = float(amount)
        claimant = (params.get("claimant") or s.get("pending_claimant")
                    or action.get("agent") or "anonymous")
        service = params.get("service") or s.get("pending_service") or "unspecified"
        claims.append({
            "id": cid,
            "claimant": claimant,
            "service": service,
            "amount": amount,
            "status": "submitted",
        })
        s["next_id"] = cid + 1
        # consume any perceived intake so it is not reused on the next submit
        s["pending_amount"] = None
        s["pending_claimant"] = None
        s["pending_service"] = None

    elif name == "review":
        cl = oldest_with("submitted")
        if cl is not None:
            cl["status"] = "under_review"

    elif name == "approve":
        cl = oldest_with("under_review")
        if cl is not None:
            cl["status"] = "approved"

    elif name == "deny":
        cl = oldest_with("under_review")
        if cl is not None:
            cl["status"] = "denied"
    # any other action name is a no-op: the world is left unchanged

    def n(status):
        return sum(1 for cl in claims if cl.get("status") == status)

    s["claims"] = claims
    s["submitted_count"] = n("submitted")
    s["under_review_count"] = n("under_review")
    s["approved_count"] = n("approved")
    s["denied_count"] = n("denied")
    s["total_claims"] = len(claims)
    s["total_approved_amount"] = round(
        sum(cl["amount"] for cl in claims if cl.get("status") == "approved"), 2)
    s["total_denied_amount"] = round(
        sum(cl["amount"] for cl in claims if cl.get("status") == "denied"), 2)
    s["last_action"] = name
    return s

