def perceive(data):
    text = str(data)
    out = {}
    for part in text.replace("\n", ";").split(";"):
        if ":" not in part:
            continue
        key, _, val = part.partition(":")
        key = key.strip().lower()
        val = val.strip()
        if key in ("amount", "charge", "billed", "cost"):
            cleaned = val.replace("$", "").replace(",", "")
            try:
                out["pending_amount"] = float(cleaned)
            except ValueError:
                pass
        elif key in ("claimant", "patient", "member"):
            out["pending_claimant"] = val
        elif key in ("service", "procedure", "code"):
            out["pending_service"] = val
    return out
